CODE_EXAMPLE:
// Before
class Person {
  String name;
  int officeAreaCode;
  int officeNumber;
}

class Company {
  Person person;
}

// After
class Person {
  String name;
}

class Company {
  Person person;
  int areaCode;
  int number;
}

UNIT_TEST_EXAMPLE:
@Test
public void testMoveField() {
  Person person = new Person("John");
  Company company = new Company();
  company.setAreaCode(415);
  company.setNumber(9999999);

  assertEquals(415, company.getAreaCode());
  assertEquals(9999999, company.getNumber());
}
